import { stackCategories } from '../data/siteData';
import './Stack.css';

const Stack = () => (
  <section id="stack">
    <div className="container">
      <div className="stack-header">
        <div className="section-label reveal">Tech Stack</div>
        <h2 className="section-headline reveal delay-1">Our tools<br />of choice.</h2>
        <p className="section-sub reveal delay-2">
          We pick tools that let us move fast without creating future problems.
          Battle-tested, community-backed, and genuinely enjoyable to work with.
        </p>
      </div>

      <div className="stack-grid">
        {stackCategories.map((cat, i) => (
          <div className={`stack-category reveal delay-${i + 1}`} key={i}>
            <h4>{cat.category}</h4>
            <div className="stack-pills">
              {cat.pills.map((pill) => (
                <div className="stack-pill" key={pill.label}>
                  <div className={`pill-dot ${pill.dotClass}`} />
                  {pill.label}
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  </section>
);

export default Stack;
